define(["jquery","core/notification","core/str"],function($,Notification,Str){return{init:function(config){var self=this;self.config=config;self.attachEventHandlers()},attachEventHandlers:function(){var self=this;$(document).on("click",".dsl-isp-filter-btn",function(e){e.preventDefault();self.applyFilters()});$(document).on("keyup","#dsl-isp-search-input",function(e){if(e.keyCode===13){self.applyFilters()}});$(document).on("change","#dsl-isp-servicetype-filter, #dsl-isp-status-filter",function(){self.applyFilters()})},applyFilters:function(){var searchText=$("#dsl-isp-search-input").val().toLowerCase();var serviceType=$("#dsl-isp-servicetype-filter").val();var status=$("#dsl-isp-status-filter").val();$(".dsl-isp-client-card").each(function(){var card=$(this);var clientName=card.data("clientname").toLowerCase();var clientServiceType=card.data("servicetype");var clientStatus=card.data("status");var showCard=true;if(searchText&&clientName.indexOf(searchText)===-1){showCard=false}if(serviceType&&clientServiceType!==serviceType){showCard=false}if(status&&clientStatus!==status){showCard=false}if(showCard){card.show()}else{card.hide()}})}}});
